import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import axios from 'axios';
import 'leaflet/dist/leaflet.css';

// Fix Leaflet icon issue
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

const blueIcon = new L.Icon({
  iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-blue.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

const redIcon = new L.Icon({
  iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-red.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
});

const BinLocator = () => {
  const [position, setPosition] = useState([18.5204, 73.8567]); // Pune Default
  const [bins, setBins] = useState([]);
  const [loading, setLoading] = useState(true);

  const token = localStorage.getItem('token'); // Get from login
  const API_URL = 'http://localhost:5000/api/v1';

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const { latitude, longitude } = pos.coords;
          setPosition([latitude, longitude]);
          fetchBins(latitude, longitude);
        },
        () => fetchBins(18.5204, 73.8567), // Pune fallback
        { enableHighAccuracy: true }
      );
    } else {
      fetchBins(18.5204, 73.8567);
    }
  }, []);

  const fetchBins = async (lat, lng) => {
    try {
      setLoading(true);
      const res = await axios.get(
        `${API_URL}/bins/nearby?lat=${lat}&lng=${lng}&radius=20000`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setBins(res.data);
    } catch (err) {
      console.error("API Error:", err.response?.data || err.message);
      alert("Failed to load bins. Using demo data.");
      setBins([
        { id: '1', name: 'APCCI Rasta Peth', lat: 18.522, lng: 73.854, fillLevel: 30, address: 'Mittal Court, Rasta Peth, Pune' },
        { id: '2', name: 'SWaCH Kothrud', lat: 18.507, lng: 73.819, fillLevel: 60, address: 'Paud Road, Kothrud, Pune' },
        { id: '3', name: 'Kuldeep Katraj', lat: 18.480, lng: 73.859, fillLevel: 75, address: 'Ambegaon KD, Katraj, Pune' }
      ]);
    } finally {
      setLoading(false);
    }
  };

  const updateBinFill = async (binId, newFillLevel) => {
    if (!token) {
      alert("Please login to update bin!");
      return;
    }
    if (newFillLevel < 0 || newFillLevel > 100) {
      alert("Fill level must be 0-100%");
      return;
    }
    try {
      await axios.post(
        `${API_URL}/bins/update/${binId}`,
        { fillLevel: parseInt(newFillLevel) },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      alert("Bin updated successfully!");
      fetchBins(position[0], position[1]); // Refresh
    } catch (err) {
      alert("Update failed: " + (err.response?.data?.error || "Server error"));
    }
  };

  if (loading) return <div className="loading">Detecting Location...</div>;

  return (
    <div className="map-page">
      <div className="map-header">
        <h2>E-Waste Bins Near You</h2>
        <p>{bins.length} bin(s) found</p>
      </div>
      <MapContainer center={position} zoom={13} className="map-container">
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
        
        {/* Your Location */}
        <Marker position={position} icon={blueIcon}>
          <Popup><b>You Are Here</b></Popup>
        </Marker>

        {/* All Bins */}
        {bins.map(bin => (
          <Marker key={bin.id} position={[bin.lat, bin.lng]} icon={redIcon}>
            <Popup>
              <div className="bin-popup">
                <h4>{bin.name}</h4>
                <p><strong>Address:</strong> {bin.address}</p>
                <p><strong>Fill Level:</strong> {bin.fillLevel}%</p>
                <div className="fill-bar">
                  <div 
                    style={{ 
                      width: `${bin.fillLevel}%`,
                      backgroundColor: bin.fillLevel > 80 ? '#e74c3c' : bin.fillLevel > 50 ? '#f39c12' : '#27ae60'
                    }} 
                  />
                </div>
                <button 
                  onClick={() => window.open(`https://www.google.com/maps/dir/${position[0]},${position[1]}/${bin.lat},${bin.lng}`)}
                  className="directions-btn"
                >
                  GET DIRECTIONS
                </button>

                {/* Update Fill Level */}
                <div className="update-section">
                  <h5>Update Fill Level:</h5>
                  <input 
                    type="number" 
                    min="0" 
                    max="100" 
                    defaultValue={bin.fillLevel}
                    id={`fill-${bin.id}`}
                    className="fill-input"
                  />
                  <button 
                    onClick={() => {
                      const input = document.getElementById(`fill-${bin.id}`);
                      updateBinFill(bin.id, input.value);
                    }} 
                    className="update-btn"
                  >
                    UPDATE
                  </button>
                </div>
              </div>
            </Popup>
          </Marker>
        ))}
      </MapContainer>
    </div>
  );
};

export default BinLocator;
